1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	export function claimOffice(input: any): unknown {
14	  const items = input.steps[0].items;
15	  let basePremium = items.reduce(
16	    (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],
17	    0
18	  );
19	
20	  const typeCounts: Record<string, number> = {};
21	  for (const item of items) {
22	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
23	  }
24	  for (const type in typeCounts) {
25	    if (typeCounts[type] === 3) {
26	      basePremium = basePremium - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
27	    }
28	  }
29	
30	  const premium = basePremium + PROCESSING_FEE;
31	  return { results: [{ premium }] };
32	}
